{
  "terms": [
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety measure that automatically cuts off power during a fault to prevent electric shock.",
      "anchor": "The 'safety trip' mechanism of the installation.",
      "misconception": "Thinking ADS is a single part; it is actually a system of coordinated components working together."
    },
    {
      "term": "TT System",
      "simpleDefinition": "An earthing system where the installation is connected to earth via its own local electrode in the ground.",
      "anchor": "Terre-Terre: Earth at the source and Earth at the house.",
      "misconception": "Believing the supplier provides the earth connection in a TT system."
    },
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing system where the supplier provides a separate, dedicated earth conductor back to the source.",
      "anchor": "S stands for Separate earth and neutral conductors.",
      "misconception": "Confusing the cable sheath earth with a combined neutral-earth conductor."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "An earthing system where the supply neutral and earth are combined into one conductor before being separated at the intake.",
      "anchor": "C for Combined (in the street), S for Separate (in the house).",
      "misconception": "Thinking the earth and neutral remain combined throughout the internal wiring of the building."
    },
    {
      "term": "Circuit Protective Conductor (CPC)",
      "simpleDefinition": "The specific wire within a circuit that connects metal parts to the main earthing terminal.",
      "anchor": "The green and yellow wire inside a standard cable.",
      "misconception": "Using the term 'earthing conductor' when referring to a circuit's CPC."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's Main Earthing Terminal to the means of earthing.",
      "anchor": "The 'main link' between the consumer unit and the earth source.",
      "misconception": "Thinking the CPC and the earthing conductor are the same thing."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors used to connect metal service pipes (like gas or water) to the Main Earthing Terminal.",
      "anchor": "Connecting the pipes to the earth bar.",
      "misconception": "Thinking bonding is designed to carry circuit fault current like a CPC does."
    },
    {
      "term": "Supplementary Bonding",
      "simpleDefinition": "Additional local earth connections used in high-risk areas, such as bathrooms, to connect metal parts together.",
      "anchor": "Local safety bonding for specific rooms.",
      "misconception": "Thinking supplementary bonding is a substitute for main protective bonding."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod or plate driven into the ground to provide a physical connection to the earth.",
      "anchor": "The copper rod in the ground used for TT systems.",
      "misconception": "Assuming every earthing system requires a local earth rod."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component, such as a fuse or circuit breaker, that disconnects the circuit during a fault.",
      "anchor": "The MCB or fuse that 'blows' or 'trips'.",
      "misconception": "Believing a protective device only reacts to high current usage (overload) rather than faults."
    }
  ],
  "anchorPhrases": [
    "TT uses a local electrode",
    "TN-S has a separate earth conductor",
    "TN-C-S combines neutral and earth in the supply",
    "The CPC protects the circuit",
    "The earthing conductor connects to the source",
    "Bonding connects the services"
  ],
  "misconceptionTargets": [
    "The earthing conductor and the CPC are the same thing.",
    "TN-S and TN-C-S are identical because they both use the supplier's earth.",
    "Any metal pipe connection is called a CPC.",
    "ADS is just another name for a circuit breaker."
  ]
}

{
  "teachChecks": [
    {
      "key": "203-4a-teach-check-1",
      "title": "Earthing System Types",
      "objective": "Identify and distinguish between TT, TN-S, and TN-C-S earthing systems.",
      "retrievalTextLines": [
        "In the UK, we use three main earthing systems: TT, TN-S, and TN-C-S. These letters describe how the installation connects to the ground and the power source.",
        "In a TT system, the supplier does not provide an earth connection. Instead, the installation relies on its own local earth electrode, such as a copper rod driven into the ground, to create a path to earth.",
        "In a TN-S system, the supplier provides a separate, dedicated earth conductor—often the metal sheath of the supply cable—that runs all the way back to the transformer. The 'S' stands for 'Separate'.",
        "In a TN-C-S system, the supply neutral and earth are 'Combined' into one conductor in the street, but then split into 'Separate' neutral and earth terminals at the building's intake. This is the most common modern system."
      ],
      "hint": "Focus on whether the earth and neutral are combined in the street (TN-C-S), kept separate throughout (TN-S), or if you have to provide your own rod (TT)."
    },
    {
      "key": "203-4a-teach-check-2",
      "title": "ADS Component Parts",
      "objective": "Identify the specific components that make up an ADS system.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) is a safety system made of several coordinated parts. It is not just a single device.",
        "The Circuit Protective Conductor (CPC) is the green and yellow wire inside individual circuit cables. It is distinct from the Earthing Conductor, which is the single main cable connecting the installation's Main Earthing Terminal (MET) to the earth source (like the supplier's terminal or an electrode).",
        "Main Protective Bonding connects metal service pipes, like gas and water, to the MET. Supplementary Bonding provides extra local earth connections in high-risk areas like bathrooms.",
        "The system also requires a Protective Device, such as a fuse or circuit breaker, to automatically trip the power during a fault. In TT systems, an Earth Electrode is a mandatory component to provide the physical connection to the ground."
      ],
      "hint": "Remember that the CPC is for individual circuits, while the Earthing Conductor is the main link to the source."
    }
  ]
}

